const rows = $input.all().map(item => item.json);
const reportId = $('Webhook').first().json.body.report_id;

function lastSentence(text) {
  if (!text) return text;
  const parts = text.split(/(?<=[.!?])\s+/);
  const last = parts.map(s => s.trim()).filter(Boolean).pop();
  return last || text;
}

// Handle empty results
if (rows.length === 0 || (rows.length === 1 && !rows[0].step_number && !rows[0].status)) {
  return [{ json: { report_id: reportId, steps: [], final_report: null, status: 'starting' } }];
}

// step_number=0 rows are special: final_report or formatter error
const finalRow = rows.find(r => r.step_number === 0 && r.status === 'final_report');
const formatterErrorRow = rows.find(r => r.step_number === 0 && r.status === 'error');

// Deduplicate step rows (step_number > 0) — retried steps produce multiple rows.
// Prefer 'completed' status; among equal or non-completed, keep the last (most recently inserted).
const allStepRows = rows.filter(r => r.step_number > 0);
const stepMap = new Map();
for (const r of allStepRows) {
  const existing = stepMap.get(r.step_number);
  if (!existing || r.status === 'completed' || existing.status !== 'completed') {
    stepMap.set(r.step_number, r);
  }
}
const stepRows = Array.from(stepMap.values()).sort((a, b) => a.step_number - b.step_number);

const steps = stepRows.map(r => ({
  step_number: r.step_number,
  purpose: r.purpose || '',
  dataset_id: r.dataset_id || '',
  status: r.status || 'pending',
  step_result: r.status === 'error'
    ? (r.step_result || 'Unknown error')
    : r.status === 'completed' && r.step_result
      ? lastSentence(r.step_result)
      : undefined
}));

// Determine overall status.
// Priority: final_report > formatter_error > in_progress
let status = 'in_progress';
let errorMessage = null;
if (finalRow) {
  status = 'completed';
} else if (formatterErrorRow) {
  status = 'error';
  errorMessage = formatterErrorRow.step_result || 'Formatter failed';
  const errorSteps = stepRows.filter(r => r.status === 'error');
  if (errorSteps.length > 0) {
    errorMessage += '\n\nStep errors: ' + errorSteps.map(r => 'Step ' + r.step_number + ': ' + (r.step_result || 'failed')).join('; ');
  }
}

return [{
  json: {
    report_id: reportId,
    steps,
    final_report: finalRow ? finalRow.step_result : null,
    status,
    error_message: errorMessage
  }
}];

